/*
 * erf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly erf  (test_erf_opt.elf)
 *   2. Linked with toolchain's default erf       (test_erf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;

static void emit(double x)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += erf(vx);
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#else
static void emit(double x)
{
    double r = erf(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#endif

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf -> erf = +1 */
    emit_u(0xfff0000000000000ULL);  /* -Inf -> erf = -1 */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);                  /* 2^-1022, smallest normal */
    emit(-DBL_MIN);
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX: 0x7fefffffffffffff -> erf saturates to 1 */

    /* --- Section 4: Near 1.0 density (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3fefffff00000000ULL);  /* a few ULPs below 1.0 */
    emit_u(0x3ff0000100000000ULL);  /* a few ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 */
    emit_u(0x3fdffffffffffffeULL);  /* one ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0x4000000000000000ULL);  /* 2.0 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */

    /* --- Section 6: erf-specific mathematical values (14) --- */
    /* erf known exact/near-exact results */
    emit(0.5);                      /* erf(0.5) ~ 0.5205 */
    emit(-0.5);
    emit(1.5);                      /* erf(1.5) ~ 0.9661 */
    emit(-1.5);
    emit(2.0);                      /* erf(2.0) ~ 0.9953 */
    emit(-2.0);
    emit(0.1);                      /* erf near-linear region */
    emit(-0.1);
    emit(0.01);
    emit(-0.01);
    emit(0.001);
    emit(-0.001);
    emit_u(0x3fe20dd750429b6dULL);  /* 2/sqrt(pi) ~ 1.1284: argument where Taylor is exact */
    emit_u(0xbfe20dd750429b6dULL);  /* negative of above */

    /* --- Section 7: Saturation region (8) --- */
    emit(2.5);                      /* erf(2.5) ~ 0.99959 */
    emit(-2.5);
    emit(3.0);                      /* erf(3.0) ~ 0.99998 */
    emit(-3.0);
    emit(4.0);                      /* erf(4.0) rounds to 1.0 in double */
    emit(-4.0);
    emit(5.0);                      /* erf(5.0) = 1.0 to double precision */
    emit(-5.0);

    /* --- Section 8: ULP neighbors of key transition points (12) --- */
    /* erf transitions from polynomial to asymptotic near x = 0.84 (erfinv(0.5)) */
    /* and again near x ~ 1.0 (polynomial switchover in many implementations) */
    emit_u(0x3feae89f995ad3adULL);  /* erfinv(0.5) ~ 0.4769: lower polynomial boundary */
    emit_u(0x3feae89f995ad3aeULL);  /* one ULP above */
    emit_u(0x3feae89f995ad3acULL);  /* one ULP below */
    /* x ~ sqrt(2): another implementation branch */
    emit_u(0x3ff6a09e667f3bccULL);  /* sqrt(2) - 1 ULP */
    emit_u(0x3ff6a09e667f3bcdULL);  /* sqrt(2) */
    emit_u(0x3ff6a09e667f3bceULL);  /* sqrt(2) + 1 ULP */
    /* near x = 4.0: saturation boundary */
    emit_u(0x400ffffffffffffeULL);  /* 4.0 - 1 ULP */
    emit_u(0x4010000000000000ULL);  /* 4.0 */
    emit_u(0x4010000000000001ULL);  /* 4.0 + 1 ULP */
    /* near x = 0.0: critical for linear approx */
    emit_u(0x3cb0000000000000ULL);  /* 2^-52: one ULP of 1.0, tests tiny-arg path */
    emit_u(0x3c90000000000000ULL);  /* 2^-54 */
    emit_u(0xbc90000000000000ULL);  /* -2^-54 */

    /* --- Section 9: Small-argument fast-path thresholds (8) --- */
    /* Many implementations use erf(x) ~ (2/sqrt(pi))*x below a threshold */
    emit_u(0x3fb0000000000000ULL);  /* 2^-4 ~ 0.0625 */
    emit_u(0xbfb0000000000000ULL);  /* -2^-4 */
    emit_u(0x3f50000000000000ULL);  /* 2^-10 ~ 0.000977 */
    emit_u(0xbf50000000000000ULL);  /* -2^-10 */
    emit_u(0x3e50000000000000ULL);  /* 2^-26 ~ 1.49e-8 */
    emit_u(0xbe50000000000000ULL);  /* -2^-26 */
    emit_u(0x3c00000000000000ULL);  /* 2^-63: extremely small, erf(x) ~ x */
    emit_u(0xbc00000000000000ULL);  /* -2^-63 */

    /* --- Section 10: Hard cases and polynomial branch points (27) --- */
    /* Large values beyond saturation: erf = +-1 exactly */
    emit(10.0);
    emit(-10.0);
    emit(100.0);
    emit(-100.0);
    /* Intermediate values spanning polynomial regions */
    emit(0.25);
    emit(-0.25);
    emit(0.75);
    emit(-0.75);
    emit(1.25);
    emit(-1.25);
    emit(1.75);
    emit(-1.75);
    emit(2.25);
    emit(-2.25);
    emit(2.75);
    emit(-2.75);
    emit(3.5);
    emit(-3.5);
    /* Power-of-2 inputs: clean exponent boundaries */
    emit(4.0);
    emit(-4.0);
    emit(8.0);
    emit(-8.0);
    emit_u(0x3fe8000000000000ULL);  /* 0.75 */
    emit_u(0x3ff4000000000000ULL);  /* 1.25 */
    emit_u(0x3ff8000000000000ULL);  /* 1.5 */
    emit_u(0x4008000000000000ULL);  /* 3.0 (duplicate check: also tested in Section 7) */
    emit_u(0x400c000000000000ULL);  /* 3.5 */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [-10, 10] in 200 steps */
static void test_sweep(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    /* [-10, 10] */
    for (int i = -nsteps; i <= nsteps; i++)
        emit((double)i * step);
}

/* 8. Sample [0, 5] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fe0000000000000ULL, /* 0.5 */
        0x3ff0000000000000ULL, /* 1.0 */
        0x3ff8000000000000ULL, /* 1.5 */
        0x4000000000000000ULL, /* 2.0 */
        0x4008000000000000ULL, /* 3.0 */
        0x4010000000000000ULL, /* 4.0 */
        0x4014000000000000ULL, /* 5.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -3.0;
    double hi =  3.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

